    }
    const uint32_t N  = static_cast<uint32_t>(xDims[0]);
    const uint32_t Ci = static_cast<uint32_t>(xDims[1]);
    const uint32_t W  = static_cast<uint32_t>(xDims[2]);
    const uint32_t H  = static_cast<uint32_t>(xDims[3]);
    const uint32_t D  = static_cast<uint32_t>(xDims[4]);

    // Weight: [C_out, C_in, K_w, K_h, K_d]
    const gert::Shape *wShape = context->GetInputShape(1);
    const auto &wDims = wShape->GetOriginShape().GetDims();
    if (wDims.size() != 5) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t Co = static_cast<uint32_t>(wDims[0]);
    const uint32_t Ci_w = static_cast<uint32_t>(wDims[1]);
    const uint32_t Kw = static_cast<uint32_t>(wDims[2]);
    const uint32_t Kh = static_cast<uint32_t>(wDims[3]);
    const uint32_t Kd = static_cast<uint32_t>(wDims[4]);
    if (Ci_w != Ci) {
        return ge::GRAPH_FAILED;
    }

    // Valid convolution (stride=1, padding=0, dilation=1)
    if (Kw == 0 || Kh == 0 || Kd == 0 || W < Kw || H < Kh || D < Kd) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t Wout = W - Kw + 1;
    const uint32_t Hout = H - Kh + 1;
    const uint32_t Dout = D - Kd + 1;

    // UB model:
    // yAcc: tileD
    // xTile: tileD + Kd - 1
    // xSeg: tileD
    // Total floats ~ (3 * tileD + (Kd - 1)), bytes = 4 * (3 * tileD + Kd - 1)
    static constexpr uint32_t UB_BUDGET_BYTES = 160 * 1024; // per-core budget
    uint32_t maxTileD = 0;
    if (Kd > 0) {
        const uint32_t usableFloats = UB_BUDGET_BYTES / 4;
        if (usableFloats > (Kd - 1)) {
            maxTileD = (usableFloats - (Kd - 1)) / 3;
        }
    }
    if (maxTileD == 0) {
        maxTileD = Dout > 0 ? (Dout < 16 ? Dout : 16u) : 1u;
    }
    // Align tileD down to 64 for better DMA behavior, but keep >= 8
    maxTileD = AlignDown(maxTileD, 64u);
    if (maxTileD < 8u) maxTileD = (Dout < 8 ? Dout : 8u);
    if (maxTileD > Dout) maxTileD = Dout;

    const uint64_t tasks = static_cast<uint64_t>(N) * Co * Wout * Hout;
    uint32_t blockDim = 1u;
    if (tasks > 0) {
        blockDim = static_cast<uint32_t>(tasks);
        if (blockDim < 8u) blockDim = 8u;
        if (blockDim > 24u) blockDim = 24u;
    }
    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cin(Ci);
    tiling.set_cout(Co);
    tiling.set_w(W);
    tiling.set_h(H);
    tiling.set_d(D);
    tiling.set_kw(Kw);
    tiling.set_kh(Kh);
    tiling.set_kd(Kd);
    tiling.set_wout(Wout);
    tiling.set_hout(Hout);
    tiling.set_dout(Dout);
    tiling.set_tileD(maxTileD);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
