static inline std::vector<int64_t> infer_out_shape_5d(const at::Tensor& x, const at::Tensor& w)
{
    // x: [N, Ci, W, H, D]; w: [Co, Ci, Kw, Kh, Kd]
    TORCH_CHECK(x.dim() == 5 && w.dim() == 5, \"expect 5D tensors\");
    TORCH_CHECK(x.scalar_type() == at::kFloat && w.scalar_type() == at::kFloat, \"only float32 supported\");
    const auto N  = x.size(0);
    const auto Ci = x.size(1);
    const auto W  = x.size(2);
    const auto H  = x.size(3);
    const auto D  = x.size(4);

    const auto Co = w.size(0);
    const auto Ci_w = w.size(1);
    const auto Kw = w.size(2);
    const auto Kh = w.size(3);
    const auto Kd = w.size(4);
    TORCH_CHECK(Ci == Ci_w, \"weight Cin mismatch with input Cin\");
    TORCH_CHECK(Kw > 0 && Kh > 0 && Kd > 0, \"kernel sizes must be > 0\");
    TORCH_CHECK(W >= Kw && H >= Kh && D >= Kd, \"kernel larger than input dims without padding\");

    const auto Wout = W - Kw + 1;
    const auto Hout = H - Kh + 1;
    const auto Dout = D - Kd + 1;
    return {N, Co, Wout, Hout, Dout};
}

at::Tensor conv3d_valid_layout_whd_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    auto out_sizes = infer_out_shape_5d(x, weight);
    at::Tensor y = at::empty(out_sizes, x.options());
    EXEC_NPU_CMD(aclnnConvStandard3dSquareInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

